def trimmed_mean(nums):
    if not nums:
        return None

    nums.sort()
    if len(nums) < 3:
        return sum(nums[1:-1]) / (len(nums[1:-1]) if len(nums[1:-1]) else 2)

    min_occurrences = nums.count(min(nums))
    max_occurrences = nums.count(max(nums))

    if min_occurrences >= 2 or max_occurrences >= 2:
        return sum(nums[1: -1]) / (len(nums[1:-1]) if len(nums[1:-1]) else 2)

    # edge case: when min and max each appear only once, we drop one of them arbitrarily
    nums.remove(min(nums))
    nums.remove(max(nums))
    return sum(nums) / (len(nums) if len(nums) > 1 else None)
